import { Request, Response } from 'express';
import { createTask, updateTaskAvailability, rerollTask } from './service';
import { AppError } from '../../middlewares/error-handler';
import { taskSchema, rerollSchema } from './validators';
import { validate } from '../../middlewares/validate';

export const createTaskHandler = async (req: Request, res: Response) => {
    try {
        validate(taskSchema, req.body);
        const task = await createTask(req.body);
        res.status(201).json(task);
    } catch (err) {
        res.status(err.statusCode || 500).json(new AppError(err));
    }
};

export const updateTaskAvailabilityHandler = async (req: Request, res: Response) => {
    try {
        validate(taskSchema, req.body);
        const task = await updateTaskAvailability(req.params.id, req.body);
        res.status(200).json(task);
    } catch (err) {
        res.status(err.statusCode || 500).json(new AppError(err));
    }
};

export const rerollTaskHandler = async (req: Request, res: Response) => {
    try {
        validate(rerollSchema, req.body);
        const task = await rerollTask(req.params.id);
        res.status(200).json(task);
    } catch (err) {
        res.status(err.statusCode || 500).json(new AppError(err));
    }
};

import { ObjectId } from 'mongodb';
import { TaskRepository } from './repository';
import { TaskDto } from './dto';

export const createTask = async (taskDto: TaskDto) => {
    const task = await TaskRepository.create(taskDto);
    return TaskDto.fromEntity(task);
};

export const updateTaskAvailability = async (taskId: ObjectId, updates: Partial<TaskDto>) => {
    const task = await TaskRepository.updateAvailability(taskId, updates);
    return TaskDto.fromEntity(task);
};

export const rerollTask = async (taskId: ObjectId) => {
    const task = await TaskRepository.reroll(taskId);
    return TaskDto.fromEntity(task);
};

import { ObjectId } from 'mongodb';
import db from '../../db';
import { TaskModel } from './model';

export const TaskRepository = {
    create: async (taskDto: any) => {
        const task = new TaskModel(taskDto);
        await task.save();
        return task;
    },
    updateAvailability: async (taskId: ObjectId, updates: any) => {
        return TaskModel.findByIdAndUpdate(taskId, updates, { new: true });
    },
    reroll: async (taskId: ObjectId) => {
        const task = await TaskModel.findById(taskId);
        if (!task) throw new Error('Task not found');

        // Implement Reroll Logic: Shuffle and update rotationIndex
        task.assignees = shuffle(task.assignees);
        task.rotationIndex = 0;
        await task.save();

        return task;
    }
};

function shuffle(array: any[]) {
    let currentIndex = array.length, randomIndex;

    while (currentIndex !== 0) {
        randomIndex = Math.floor(Math.random() * currentIndex);
        currentIndex--;

        [array[currentIndex], array[randomIndex]] = [array[randomIndex], array[currentIndex]];
    }

    return array;
}

import { Task } from './model';
import { ObjectId } from 'mongodb';

export interface TaskDto {
    id?: ObjectId;
    groupId: ObjectId;
    title: string;
    description: string;
    assignees: ObjectId[];
    rotationIndex: number;
    unavailableMembers?: ObjectId[];
    recurrence: {
        type: 'daily' | 'weekly' | 'custom';
        daysOfWeek?: number[];
        time: string;
    };
    status: 'active' | 'paused';
}

export class TaskDto {
    static fromEntity(task: Task): TaskDto {
        return {
            id: task.id,
            groupId: task.groupId,
            title: task.title,
            description: task.description,
            assignees: task.assignees,
            rotationIndex: task.rotationIndex,
            unavailableMembers: task.unavailableMembers,
            recurrence: task.recurrence,
            status: task.status
        };
    }
}

import { z, ZodObject } from 'zod';

export const taskSchema: ZodObject = z.object({
    groupId: z.string().min(1),
    title: z.string().min(1),
    description: z.string().min(1),
    assignees: z.array(z.string().min(1)),
    rotationIndex: z.number().nonnegative(),
    unavailableMembers: z.array(z.string().min(1)).optional(),
    recurrence: z.object({
        type: z.enum(['daily', 'weekly', 'custom']),
        daysOfWeek: z.array(z.number()).min(0).max(6).optional(),
        time: z.string().regex(/^\d{2}:\d{2}$/)
    }),
    status: z.enum(['active', 'paused'])
});

export const rerollSchema: ZodObject = z.object({
    taskId: z.string().min(1)
});
